// m4 fallback: reconstruct from Chromium's OWN flattened view via CDP
// `DOMSnapshot.captureSnapshot`. This is the only method that recovers CLOSED
// shadow DOM (Chromium flattens the rendered tree regardless of JS
// encapsulation) and is CSP-robust (resources are transported out-of-page via
// Playwright's request context, not in-page fetch). It is BLIND to canvas/WebGL/
// video pixels (structural method, no sidecars) — m7 stays primary for those.
//
// Clean reimplementation of fidelity-lab/methods/m4_domsnapshot.mjs.

import type { CDPSession, Page } from "playwright-core";

import { resolveResourceUris } from "./resources.js";
import type { CaptureSnapshot } from "./types.js";

// Visually load-bearing computed properties — same curated set m7 inlines, so the
// method comparison isolates the SOURCE of the styles, not the prop list.
const PROPS = [
  "display", "position", "top", "right", "bottom", "left", "float", "clear", "z-index",
  "box-sizing", "width", "height", "min-width", "min-height", "max-width", "max-height",
  "margin-top", "margin-right", "margin-bottom", "margin-left",
  "padding-top", "padding-right", "padding-bottom", "padding-left",
  "border-top-width", "border-right-width", "border-bottom-width", "border-left-width",
  "border-top-style", "border-right-style", "border-bottom-style", "border-left-style",
  "border-top-color", "border-right-color", "border-bottom-color", "border-left-color",
  "border-top-left-radius", "border-top-right-radius", "border-bottom-left-radius", "border-bottom-right-radius",
  "outline-width", "outline-style", "outline-color", "outline-offset",
  "color", "background-color", "background-image", "background-position", "background-size",
  "background-repeat", "background-origin", "background-clip", "background-attachment",
  "-webkit-background-clip", "-webkit-text-fill-color",
  "opacity", "visibility", "overflow-x", "overflow-y",
  "font-family", "font-size", "font-weight", "font-style", "font-stretch", "font-variant",
  "line-height", "letter-spacing", "word-spacing", "text-align", "text-transform",
  "text-decoration", "text-decoration-color", "text-decoration-line", "text-decoration-style",
  "text-shadow", "text-indent", "white-space", "word-break", "overflow-wrap",
  "vertical-align", "list-style", "direction", "writing-mode", "unicode-bidi",
  "box-shadow", "filter", "backdrop-filter", "mix-blend-mode", "isolation",
  "transform", "transform-origin", "perspective", "transform-style",
  "clip-path", "-webkit-clip-path", "mask", "-webkit-mask", "-webkit-mask-image",
  "flex-direction", "flex-wrap", "flex-grow", "flex-shrink", "flex-basis", "order",
  "justify-content", "align-items", "align-content", "align-self", "justify-self", "gap", "row-gap", "column-gap",
  "grid-template-columns", "grid-template-rows", "grid-template-areas", "grid-column", "grid-row",
  "grid-auto-flow", "grid-auto-columns", "grid-auto-rows",
  "aspect-ratio", "object-fit", "object-position", "content",
  "border-collapse", "border-spacing", "table-layout",
];

const NOISE = new Set(["auto", "normal", "none", ""]);
const SVG_TAGS = new Set([
  "svg", "g", "path", "rect", "circle", "ellipse", "line", "polyline", "polygon",
  "text", "tspan", "defs", "use", "symbol", "clippath", "lineargradient",
  "radialgradient", "stop", "mask", "pattern", "image", "marker", "filter",
  "fegaussianblur", "feoffset", "feblend", "femerge", "femergenode", "fecolormatrix",
  "fecomposite", "fedropshadow", "foreignobject", "title", "desc", "textpath",
]);
const VOID = new Set(["area", "base", "br", "col", "embed", "hr", "img", "input", "link", "meta", "param", "source", "track", "wbr"]);

const escAttr = (s: string): string => String(s).replace(/&/g, "&amp;").replace(/"/g, "&quot;").replace(/</g, "&lt;");
const escText = (s: string): string => String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");

// Loosely-typed view of the CDP DOMSnapshot payload (the protocol arrays are
// parallel/interned; full typing buys nothing here).
type Snap = {
  strings: string[];
  documents: Array<{
    nodes: Record<string, number[] | { index: number[] }>;
    layout: { nodeIndex: number[]; styles: number[][]; bounds?: number[][] };
    baseURL?: number;
    documentURL?: number;
    scrollOffsetX?: number;
    scrollOffsetY?: number;
    contentWidth?: number;
  }>;
};

/** Harvest @font-face data-URIs in-page (DOMSnapshot doesn't expose sheet text). */
/* istanbul ignore next -- runs in the browser */
function harvestFontFaceInPage(): Promise<string> {
  const sameOrigin = (u: string): boolean => { try { return new URL(u, location.href).origin === location.origin; } catch { return false; } };
  const blocks: (string | null)[] = [];
  const tasks: Promise<unknown>[] = [];
  const mime = (u: string): string =>
    /\.woff2/i.test(u) ? "woff2" : /\.woff/i.test(u) ? "woff" : /\.(ttf|truetype)/i.test(u) ? "truetype" : /\.(otf|opentype)/i.test(u) ? "opentype" : "woff2";
  async function toDataUri(abs: string): Promise<string | null> {
    try {
      const r = await fetch(abs, { mode: sameOrigin(abs) ? "same-origin" : "cors" });
      if (!r.ok) return null;
      const b = await r.blob();
      return await new Promise<string | null>((res) => { const fr = new FileReader(); fr.onload = () => res(fr.result as string); fr.onerror = () => res(null); fr.readAsDataURL(b); });
    } catch { return null; }
  }
  function fromText(cssText: string, base: string): void {
    const re = /@font-face\s*\{([^}]*)\}/gi; let m: RegExpExecArray | null;
    while ((m = re.exec(cssText))) {
      const body = m[1] ?? "";
      const g = (p: string): string => { const r = new RegExp(p + "\\s*:\\s*([^;]+)", "i").exec(body); return r ? (r[1] ?? "").trim() : ""; };
      const um = g("src").match(/url\((['"]?)([^'")]+)\1\)/); if (!um) continue;
      let abs: string; try { abs = new URL(um[2]!, base).href; } catch { continue; }
      const idx = blocks.length; blocks.push(null);
      tasks.push(toDataUri(abs).then((d) => { if (d) blocks[idx] = `@font-face{font-family:${g("font-family")};font-style:${g("font-style") || "normal"};font-weight:${g("font-weight") || "normal"};font-display:block;src:url(${d}) format('${mime(abs)}');}`; }));
    }
  }
  function walk(sheet: CSSStyleSheet): void {
    let rules: CSSRuleList | undefined;
    try { rules = sheet.cssRules; } catch {
      if (sheet.href) tasks.push(fetch(sheet.href, { mode: "cors" }).then((r) => (r.ok ? r.text() : "")).then((t) => t && fromText(t, sheet.href!)).catch(() => {}));
      return;
    }
    if (!rules) return;
    for (const rule of Array.from(rules)) {
      if (rule.type === CSSRule.IMPORT_RULE) {
        const ir = rule as CSSImportRule;
        let ok = false; try { ok = !!(ir.styleSheet && ir.styleSheet.cssRules); } catch { /* opaque */ }
        if (ok && ir.styleSheet) walk(ir.styleSheet);
        else { let h = ir.href; try { h = new URL(ir.href, sheet.href || location.href).href; } catch { /* keep */ } if (h) tasks.push(fetch(h, { mode: "cors" }).then((r) => (r.ok ? r.text() : "")).then((t) => t && fromText(t, h)).catch(() => {})); }
      } else if (rule.type === CSSRule.FONT_FACE_RULE) {
        const fr = rule as CSSFontFaceRule;
        const src = fr.style.getPropertyValue("src"); if (!src) continue;
        const um = src.match(/url\((['"]?)([^'")]+)\1\)/); if (!um) continue;
        if (um[2]!.startsWith("data:")) { blocks.push(`@font-face{${fr.style.cssText}}`); continue; }
        let abs: string; try { abs = new URL(um[2]!, sheet.href || location.href).href; } catch { continue; }
        const fam = fr.style.getPropertyValue("font-family");
        const wt = fr.style.getPropertyValue("font-weight") || "normal";
        const st = fr.style.getPropertyValue("font-style") || "normal";
        const idx = blocks.length; blocks.push(null);
        tasks.push(toDataUri(abs).then((d) => { if (d) blocks[idx] = `@font-face{font-family:${fam};font-style:${st};font-weight:${wt};font-display:block;src:url(${d}) format('${mime(abs)}');}`; }));
      }
    }
  }
  for (const s of Array.from(document.styleSheets)) walk(s as CSSStyleSheet);
  return Promise.all(tasks).then(() => blocks.filter(Boolean).join("\n"));
}

export async function snapshotM4(page: Page): Promise<CaptureSnapshot> {
  const client: CDPSession = await page.context().newCDPSession(page);
  let snap: Snap;
  try {
    await client.send("DOMSnapshot.enable").catch(() => {});
    snap = (await client.send("DOMSnapshot.captureSnapshot", {
      computedStyles: PROPS,
      includePaintOrder: true,
      includeDOMRects: true,
    })) as unknown as Snap;
  } finally {
    await client.detach().catch(() => {});
  }

  const strings = snap.strings;
  const doc = snap.documents[0]!;
  const nodes = doc.nodes as Record<string, number[]> & { inputChecked?: { index: number[] } };
  const nodeType = nodes["nodeType"] as number[];
  const nodeName = nodes["nodeName"] as number[];
  const nodeValue = nodes["nodeValue"] as number[];
  const parentIndex = nodes["parentIndex"] as number[];
  const attributesArr = nodes["attributes"] as unknown as number[][];
  const pseudoType = nodes["pseudoType"] as number[] | undefined;
  const currentSourceURL = nodes["currentSourceURL"] as number[] | undefined;
  const inputValue = nodes["inputValue"] as number[] | undefined;
  const inputCheckedIndex = (nodes as { inputChecked?: { index: number[] } }).inputChecked?.index;
  const layout = doc.layout;
  const S = (i: number | undefined | null): string | null => (i != null && i >= 0 ? strings[i]! : null);

  // styleByNode: nodeIndex -> {css, bag}
  const styleByNode = new Map<number, { css: string; bag: Record<string, string> }>();
  for (let j = 0; j < layout.nodeIndex.length; j++) {
    const nodeIdx = layout.nodeIndex[j]!;
    const styleArr = layout.styles[j];
    if (!styleArr) continue;
    let css = "";
    const bag: Record<string, string> = {};
    for (let p = 0; p < PROPS.length; p++) {
      const v = S(styleArr[p]);
      if (v == null) continue;
      bag[PROPS[p]!] = v;
      if (NOISE.has(v)) continue;
      css += `${PROPS[p]}:${v};`;
    }
    styleByNode.set(nodeIdx, { css, bag });
  }

  const children = new Map<number, number[]>();
  for (let i = 0; i < parentIndex.length; i++) {
    const p = parentIndex[i]!;
    if (p < 0) continue;
    if (!children.has(p)) children.set(p, []);
    children.get(p)!.push(i);
  }

  function attrsOf(i: number): Map<string, string> {
    const flat = attributesArr[i] || [];
    const m = new Map<string, string>();
    for (let k = 0; k + 1 < flat.length; k += 2) {
      const name = S(flat[k]);
      const val = S(flat[k + 1]);
      if (name != null) m.set(name, val ?? "");
    }
    return m;
  }

  const resourceUrls = new Set<string>();
  const baseURL = doc.baseURL != null ? S(doc.baseURL) : doc.documentURL != null ? S(doc.documentURL) : null;
  const absUrl = (u: string | null): string | null => {
    if (!u || u.startsWith("data:")) return null;
    try { return new URL(u, baseURL || undefined).href; } catch { return null; }
  };

  function emit(i: number, inSvg: boolean): string {
    const type = nodeType[i];
    if (type === 3) { const v = S(nodeValue[i]); return v != null ? escText(v) : ""; }
    if (type === 8) return "";
    if (type !== 1) return (children.get(i) || []).map((c) => emit(c, inSvg)).join("");

    const rawName = S(nodeName[i]) || "div";
    const tag = rawName.toLowerCase();
    const pseudo = pseudoType && pseudoType[i] != null ? S(pseudoType[i]) : null;

    if (tag === "script" || tag === "noscript" || tag === "link" || tag === "meta" || tag === "base" || tag === "title") {
      return "";
    }

    const styleEntry = styleByNode.get(i);
    const bag = styleEntry ? styleEntry.bag : {};

    if (pseudo === "before" || pseudo === "after") {
      const content = bag["content"];
      if (!content || content === "none" || content === "normal") return "";
      const css = styleEntry ? styleEntry.css : "";
      const txt = String(content).replace(/^["']|["']$/g, "");
      const safeTxt = txt && txt !== "counter" && !txt.startsWith("url(") ? escText(txt) : "";
      return `<span data-pseudo="::${pseudo}" style="${escAttr(css)}">${safeTxt}</span>`;
    }
    if (pseudo) return "";

    const nowSvg = inSvg || tag === "svg" || SVG_TAGS.has(tag);

    if (tag === "style") {
      const inner = (children.get(i) || []).map((c) => emit(c, false)).join("");
      return `<style>${inner}</style>`;
    }

    const attrs = attrsOf(i);
    let attrStr = "";
    for (const a of ["class", "id", "dir", "lang", "role", "viewBox", "width", "height",
      "d", "points", "x", "y", "x1", "y1", "x2", "y2", "cx", "cy", "r", "rx", "ry", "fill",
      "stroke", "stroke-width", "transform", "offset", "stop-color", "gradientUnits",
      "href", "xlink:href", "preserveAspectRatio", "clip-path", "aria-hidden"]) {
      if (attrs.has(a)) attrStr += ` ${a}="${escAttr(attrs.get(a)!)}"`;
    }

    const css = styleEntry ? styleEntry.css : "";
    const bg = bag["background-image"];
    if (bg && bg.includes("url(")) {
      const m = bg.match(/url\((['"]?)(.*?)\1\)/);
      const abs = m && absUrl(m[2] ?? null);
      if (abs) resourceUrls.add(abs);
    }

    if (tag === "img") {
      const src = (currentSourceURL && S(currentSourceURL[i])) || attrs.get("src") || "";
      const abs = absUrl(src);
      if (abs) { resourceUrls.add(abs); attrStr += ` src="${escAttr(abs)}"`; }
      else if (src) attrStr += ` src="${escAttr(src)}"`;
      if (attrs.has("alt")) attrStr += ` alt="${escAttr(attrs.get("alt")!)}"`;
      return `<img${attrStr} style="${escAttr(css)}">`;
    }

    if (tag === "input" || tag === "textarea" || tag === "select") {
      const iv = inputValue && S(inputValue[i]);
      if (iv != null) attrStr += ` value="${escAttr(iv)}"`;
      if (inputCheckedIndex && inputCheckedIndex.includes(i)) attrStr += " checked";
      if (attrs.has("type")) attrStr += ` type="${escAttr(attrs.get("type")!)}"`;
      if (attrs.has("placeholder")) attrStr += ` placeholder="${escAttr(attrs.get("placeholder")!)}"`;
    }

    const styleAttr = css ? ` style="${escAttr(css)}"` : "";
    const open = `<${tag}${attrStr}${styleAttr}>`;
    if (VOID.has(tag)) return open;
    const kids = (children.get(i) || []).map((c) => emit(c, nowSvg)).join("");
    return `${open}${kids}</${tag}>`;
  }

  let htmlIdx = -1, bodyIdx = -1, headIdx = -1;
  for (let i = 0; i < nodeName.length; i++) {
    const nm = (S(nodeName[i]) || "").toLowerCase();
    if (nm === "html" && htmlIdx < 0) htmlIdx = i;
    if (nm === "body" && bodyIdx < 0) bodyIdx = i;
    if (nm === "head" && headIdx < 0) headIdx = i;
  }

  const htmlStyle = htmlIdx >= 0 && styleByNode.get(htmlIdx) ? styleByNode.get(htmlIdx)!.css : "";
  const bgColor =
    (htmlIdx >= 0 ? styleByNode.get(htmlIdx)?.bag["background-color"] : undefined) ||
    (bodyIdx >= 0 ? styleByNode.get(bodyIdx)?.bag["background-color"] : undefined) ||
    "#ffffff";

  let headStyles = "";
  if (headIdx >= 0) {
    for (const c of children.get(headIdx) || []) {
      if ((S(nodeName[c]) || "").toLowerCase() === "style") headStyles += emit(c, false);
    }
  }

  const bodyHtml = bodyIdx >= 0 ? emit(bodyIdx, false) : "";
  const fontFaceCss = await page.evaluate(harvestFontFaceInPage).catch(() => "");

  // Transport image/background resources as data-URIs via Playwright's request
  // context (CSP-immune — we drive the browser, not the page). Shared with m7.
  const dataUris = await resolveResourceUris(page, resourceUrls);

  let html = bodyHtml;
  for (const [u, d] of Object.entries(dataUris)) {
    html = html.split(`src="${escAttr(u)}"`).join(`src="${d}"`);
    html = html.split(u).join(d);
  }

  const out =
    `<!doctype html><html style="${escAttr(htmlStyle)}">` +
    `<head><meta charset="utf-8"><meta name="viewport" content="width=${doc.contentWidth || ""}">` +
    `<style>html,body{margin:0;background:${bgColor};}*{box-sizing:border-box;}[data-pseudo]{display:inline-block;}</style>` +
    (headStyles ? `<style>${headStyles}</style>` : "") +
    (fontFaceCss ? `<style>${fontFaceCss}</style>` : "") +
    `</head>${html}</html>`;

  return {
    method: "m4",
    html: out,
    scrolls: [{ sel: ":root", x: doc.scrollOffsetX || 0, y: doc.scrollOffsetY || 0 }],
    surfaces: [],
    notes: `CDP DOMSnapshot: ${layout.nodeIndex.length} laid-out nodes, ${Object.keys(dataUris).length} resources inlined; canvas/webgl/video are blind (structural method)`,
  };
}
