import { execFile } from "node:child_process";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

export type RenderFormat = "mp4" | "webm" | "poster" | "gif";

export async function transcodeMp4(input: string, output: string): Promise<string> {
  await runFfmpeg([
    "-y",
    "-i",
    input,
    "-c:v",
    "libx264",
    "-pix_fmt",
    "yuv420p",
    "-movflags",
    "+faststart",
    output,
  ]);
  return output;
}

export async function transcodeWebm(input: string, output: string): Promise<string> {
  await runFfmpeg([
    "-y",
    "-i",
    input,
    "-c:v",
    "libvpx-vp9",
    "-b:v",
    "0",
    "-crf",
    "34",
    "-pix_fmt",
    "yuv420p",
    output,
  ]);
  return output;
}

export async function extractPoster(input: string, output: string): Promise<string> {
  await runFfmpeg([
    "-y",
    "-i",
    input,
    "-frames:v",
    "1",
    "-vcodec",
    "libwebp",
    "-quality",
    "85",
    output,
  ]);
  return output;
}

export async function transcodeGif(input: string, output: string): Promise<string> {
  await runFfmpeg([
    "-y",
    "-i",
    input,
    "-vf",
    "fps=12,scale=640:-1:flags=lanczos",
    output,
  ]);
  return output;
}

async function runFfmpeg(args: string[]): Promise<void> {
  try {
    await execFileAsync("ffmpeg", args, { maxBuffer: 1024 * 1024 * 16 });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(`ffmpeg failed: ${message}`);
  }
}
