// Shared DOM serialization for Tier-3 capture (clean reimplementation of the
// fidelity-lab m5_computed + m7_hybrid in-page walk — NOT an import of lab code).
//
// `serializeHybridInPage` runs *inside the page* (passed to page.evaluate, so it
// must be self-contained: every value it uses is declared inside it; only
// type-only references may point outside, since TS erases them before the
// function is stringified for the browser).
//
// It produces a JSON payload describing a self-contained reconstruction:
//   - the body serialized with curated computed styles inlined (so no external
//     stylesheet is needed on remount),
//   - @font-face rules rewritten with their font files inlined as data-URIs
//     (lab fix: web-font region 14.4% -> 2.4%),
//   - SVG subtrees preserved in the SVG namespace with external <use href> sprites
//     pulled in as <symbol> defs (lab fix: SVG sprite 36.9% -> 0.39%),
//   - un-serializable surfaces (canvas / video / cross-origin iframe ONLY) replaced
//     by geometry-preserving placeholders to be composited as rasterized sidecars
//     (lab fix: sidecar scope restricted so plain clip-path/mask stays in the DOM
//     path, 3.95% -> 0.02%).
//
// The Node side (m7-hybrid.ts) fills in sidecar pixels (inline dataURI where the
// canvas/video is readable, else a Playwright element screenshot) and bakes the
// sidecars into the final standalone HTML.

/** A reference to an external raster resource the Node side inlines (no CORS). */
export type ResourceRef = {
  /** Stable id so an unresolved <img> can be located and rasterized as a sidecar. */
  id: string;
  url: string;
  rect: SerializedSurface["rect"];
};

/** A surface that the DOM serializer cannot reproduce and must rasterize. */
export type SerializedSurface = {
  id: string;
  kind: "canvas" | "video" | "iframe";
  /** page-relative (x,y for placement) + viewport-relative (vx,vy for shots) + size. */
  rect: { x: number; y: number; vx: number; vy: number; w: number; h: number };
  /** Inline dataURI if the surface was readable in-page (untainted canvas/video). */
  dataUri: string | null;
  /** True when the Node side must take a Playwright element screenshot instead. */
  needPlaywrightShot: boolean;
  /** Carried so rounded/clipped surfaces composite faithfully. */
  clip?: { borderRadius: string; clipPath: string };
};

export type SerializedPayload = {
  rootStyle: string;
  bodyHtml: string;
  scrolls: { sel: string; x: number; y: number }[];
  surfaces: SerializedSurface[];
  /** Content <img> resources for Node-side (CORS-free) inlining; unresolved → sidecar. */
  imgRefs: ResourceRef[];
  /** Absolute background-image URLs for Node-side inlining. */
  bgUrls: string[];
  dpr: number;
  vw: number;
  vh: number;
  lang: string;
  dir: string;
  bgColor: string;
  fontFaceCss: string;
  extDefs: string;
};

/**
 * The in-page m7-hybrid serializer. Returns a JSON string (Playwright can only
 * transfer structured-cloneable values, and a single string is safest).
 */
/* istanbul ignore next -- runs in the browser, exercised via Playwright */
export function serializeHybridInPage(): Promise<string> {
  // Visually load-bearing computed properties. Inlining the full longhand set
  // bloats output ~10x and fights the cascade; this curated list paints.
  const PROPS = [
    "display", "position", "top", "right", "bottom", "left", "float", "clear", "z-index",
    "box-sizing", "width", "height", "min-width", "min-height", "max-width", "max-height",
    "margin-top", "margin-right", "margin-bottom", "margin-left",
    "padding-top", "padding-right", "padding-bottom", "padding-left",
    "border-top-width", "border-right-width", "border-bottom-width", "border-left-width",
    "border-top-style", "border-right-style", "border-bottom-style", "border-left-style",
    "border-top-color", "border-right-color", "border-bottom-color", "border-left-color",
    "border-top-left-radius", "border-top-right-radius", "border-bottom-left-radius", "border-bottom-right-radius",
    "outline-width", "outline-style", "outline-color", "outline-offset",
    "color", "background-color", "background-image", "background-position", "background-size",
    "background-repeat", "background-origin", "background-clip", "background-attachment",
    "-webkit-background-clip", "-webkit-text-fill-color",
    "opacity", "visibility", "overflow", "overflow-x", "overflow-y",
    "font-family", "font-size", "font-weight", "font-style", "font-stretch", "font-variant",
    "line-height", "letter-spacing", "word-spacing", "text-align", "text-transform",
    "text-decoration", "text-decoration-color", "text-decoration-line", "text-decoration-style",
    "text-shadow", "text-indent", "white-space", "word-break", "overflow-wrap",
    "vertical-align", "list-style", "direction", "writing-mode", "unicode-bidi",
    "box-shadow", "filter", "backdrop-filter", "mix-blend-mode", "isolation",
    "transform", "transform-origin", "perspective", "transform-style",
    "clip-path", "-webkit-clip-path", "mask", "-webkit-mask", "-webkit-mask-image",
    "mask-image", "mask-position", "mask-size", "mask-repeat", "mask-mode", "mask-composite",
    "mask-clip", "mask-origin",
    "flex-direction", "flex-wrap", "flex-grow", "flex-shrink", "flex-basis", "order",
    "justify-content", "align-items", "align-content", "align-self", "gap", "row-gap", "column-gap",
    "grid-template-columns", "grid-template-rows", "grid-template-areas", "grid-column", "grid-row",
    "grid-auto-flow", "grid-auto-columns", "grid-auto-rows",
    "aspect-ratio", "object-fit", "object-position", "content",
    "border-collapse", "border-spacing", "table-layout",
  ];

  const SVGNS = "http://www.w3.org/2000/svg";
  const XLINKNS = "http://www.w3.org/1999/xlink";

  const sameOrigin = (url: string): boolean => {
    try { return new URL(url, location.href).origin === location.origin; }
    catch { return false; }
  };

  // ---- resource references (images / background-image) ----
  // Raster resources are NOT fetched in-page (the browser's CORS sandbox rejects
  // cross-origin / redirected / no-CORS responses and taints canvas read-backs).
  // We only RECORD absolute URLs here; the Node side resolves them via
  // page.request.get (no CORS, follows redirects) and inlines them. SVG-sprite and
  // @font-face fetches stay in-page because they need CSSOM / DOMParser access.
  const fetchTasks: Promise<unknown>[] = [];
  const imgRefs: { id: string; url: string; rect: SerializedSurface["rect"] }[] = [];
  const bgUrls: string[] = [];
  let imgSeq = 0;
  const toAbs = (url: string): string | null => {
    try { return new URL(url, location.href).href; } catch { return null; }
  };

  const styleCss = (el: Element, pseudo?: string): { out: string; cs: CSSStyleDeclaration } => {
    const cs = getComputedStyle(el, pseudo ?? null);
    let out = "";
    for (const p of PROPS) {
      const v = cs.getPropertyValue(p);
      if (v && !(v === "none" && p !== "content") && v !== "auto" && v !== "normal") out += `${p}:${v};`;
    }
    return { out, cs };
  };

  // ---- SVG <use> sprites: pull external symbols inline (namespace-correct). ----
  const externalSymbols = new Map<string, string>();
  function inlineExternalUse(useEl: Element): void {
    const href =
      useEl.getAttribute("href") ||
      useEl.getAttributeNS(XLINKNS, "href") ||
      useEl.getAttribute("xlink:href") || "";
    if (!href || href.startsWith("#") || href.startsWith("data:")) return;
    const hashIdx = href.indexOf("#");
    if (hashIdx < 0) return;
    const fileUrl = href.slice(0, hashIdx);
    const symId = href.slice(hashIdx + 1);
    fetchTasks.push(
      (async () => {
        try {
          let abs: string;
          try { abs = new URL(fileUrl, location.href).href; } catch { return; }
          const resp = await fetch(abs, { mode: sameOrigin(abs) ? "same-origin" : "cors" });
          if (!resp.ok) return;
          const text = await resp.text();
          const doc = new DOMParser().parseFromString(text, "image/svg+xml");
          const sym = doc.getElementById(symId);
          if (sym) {
            externalSymbols.set(symId, sym.outerHTML);
            useEl.setAttribute("href", `#${symId}`);
          }
        } catch { /* ignore */ }
      })(),
    );
  }

  // ---- @font-face inlining (data-URI the font files so no fallback on remount). ----
  const fontFaceTasks: Promise<unknown>[] = [];
  const fontFaceBlocks: (string | null)[] = [];
  const mimeForFont = (url: string): string => {
    if (/\.woff2(\?|$)/i.test(url)) return "woff2";
    if (/\.woff(\?|$)/i.test(url)) return "woff";
    if (/\.(ttf|truetype)(\?|$)/i.test(url)) return "truetype";
    if (/\.(otf|opentype)(\?|$)/i.test(url)) return "opentype";
    return "woff2";
  };
  function emitFontFace(block: {
    family: string; style: string; weight: string; stretch: string;
    unicodeRange: string; display: string; dataUri: string; fmt: string;
  }): string {
    return (
      `@font-face{font-family:${block.family};font-style:${block.style || "normal"};` +
      `font-weight:${block.weight || "normal"};${block.stretch ? `font-stretch:${block.stretch};` : ""}` +
      `${block.unicodeRange ? `unicode-range:${block.unicodeRange};` : ""}` +
      `font-display:${block.display || "block"};src:url(${block.dataUri}) format('${block.fmt}');}`
    );
  }
  function collectFontFaceFromCssText(cssText: string, baseHref: string): void {
    const ffRe = /@font-face\s*\{([^}]*)\}/gi;
    let m: RegExpExecArray | null;
    while ((m = ffRe.exec(cssText))) {
      const body = m[1] ?? "";
      const get = (prop: string): string => {
        const r = new RegExp(prop + "\\s*:\\s*([^;]+)", "i").exec(body);
        return r ? (r[1] ?? "").trim() : "";
      };
      const src = get("src");
      const urlMatch = src.match(/url\((['"]?)([^'")]+)\1\)/);
      if (!urlMatch) continue;
      const url = urlMatch[2]!;
      const family = get("font-family");
      const idx = fontFaceBlocks.length;
      fontFaceBlocks.push(null);
      fontFaceTasks.push(
        (async () => {
          let abs: string;
          try { abs = new URL(url, baseHref || location.href).href; } catch { return; }
          try {
            const resp = await fetch(abs, { mode: sameOrigin(abs) ? "same-origin" : "cors" });
            if (!resp.ok) return;
            const blob = await resp.blob();
            const dataUri = await new Promise<string | null>((res) => {
              const fr = new FileReader();
              fr.onload = () => res(fr.result as string);
              fr.onerror = () => res(null);
              fr.readAsDataURL(blob);
            });
            if (!dataUri) return;
            fontFaceBlocks[idx] = emitFontFace({
              family, style: get("font-style"), weight: get("font-weight"),
              stretch: get("font-stretch"), unicodeRange: get("unicode-range"),
              display: get("font-display"), dataUri, fmt: mimeForFont(abs),
            });
          } catch { /* leave null */ }
        })(),
      );
    }
  }
  function collectFontFaceRules(sheet: CSSStyleSheet): void {
    let rules: CSSRuleList | undefined;
    try { rules = sheet.cssRules; } catch {
      if (sheet.href) {
        fontFaceTasks.push(
          fetch(sheet.href, { mode: "cors" })
            .then((r) => (r.ok ? r.text() : ""))
            .then((t) => { if (t) collectFontFaceFromCssText(t, sheet.href!); })
            .catch(() => {}),
        );
      }
      return;
    }
    if (!rules) return;
    for (const rule of Array.from(rules)) {
      if (rule.type === CSSRule.IMPORT_RULE) {
        const importRule = rule as CSSImportRule;
        let importedReadable = false;
        try { importedReadable = !!(importRule.styleSheet && importRule.styleSheet.cssRules); } catch { importedReadable = false; }
        if (importedReadable && importRule.styleSheet) {
          collectFontFaceRules(importRule.styleSheet);
        } else {
          let importHref = importRule.href;
          try { importHref = new URL(importRule.href, sheet.href || location.href).href; } catch { /* keep */ }
          if (importHref) {
            fontFaceTasks.push(
              fetch(importHref, { mode: "cors" })
                .then((r) => (r.ok ? r.text() : ""))
                .then((t) => { if (t) collectFontFaceFromCssText(t, importHref); })
                .catch(() => {}),
            );
          }
        }
      } else if (rule.type === CSSRule.FONT_FACE_RULE) {
        const ffRule = rule as CSSFontFaceRule;
        const src = ffRule.style.getPropertyValue("src");
        if (!src) continue;
        const urlMatch = src.match(/url\((['"]?)([^'")]+)\1\)/);
        if (!urlMatch) continue;
        const url = urlMatch[2]!;
        const family = ffRule.style.getPropertyValue("font-family");
        const weight = ffRule.style.getPropertyValue("font-weight") || "normal";
        const style = ffRule.style.getPropertyValue("font-style") || "normal";
        const stretch = ffRule.style.getPropertyValue("font-stretch") || "";
        const unicodeRange = ffRule.style.getPropertyValue("unicode-range") || "";
        const display = ffRule.style.getPropertyValue("font-display") || "block";
        if (url.startsWith("data:")) {
          fontFaceBlocks.push(`@font-face{${ffRule.style.cssText}}`);
          continue;
        }
        const idx = fontFaceBlocks.length;
        fontFaceBlocks.push(null);
        fontFaceTasks.push(
          (async () => {
            let abs: string;
            try { abs = new URL(url, sheet.href || location.href).href; } catch { return; }
            try {
              const resp = await fetch(abs, { mode: sameOrigin(abs) ? "same-origin" : "cors" });
              if (!resp.ok) return;
              const blob = await resp.blob();
              const dataUri = await new Promise<string | null>((res) => {
                const fr = new FileReader();
                fr.onload = () => res(fr.result as string);
                fr.onerror = () => res(null);
                fr.readAsDataURL(blob);
              });
              if (!dataUri) return;
              fontFaceBlocks[idx] = emitFontFace({
                family, style, weight, stretch, unicodeRange, display, dataUri, fmt: mimeForFont(abs),
              });
            } catch { /* leave null */ }
          })(),
        );
      }
    }
  }
  for (const sheet of Array.from(document.styleSheets)) collectFontFaceRules(sheet as CSSStyleSheet);

  // ---- un-serializable surface detection (canvas/video/cross-origin iframe ONLY) ----
  const surfaces: SerializedSurface[] = [];
  let surfaceSeq = 0;

  function rectOf(el: Element): SerializedSurface["rect"] {
    const r = el.getBoundingClientRect();
    return { x: r.left + window.scrollX, y: r.top + window.scrollY, vx: r.left, vy: r.top, w: r.width, h: r.height };
  }
  // Sidecars are NESTED inside their placeholder (position:absolute;inset:0), so
  // the placeholder MUST be a containing block. The placeholder carries the
  // original element's computed style INLINE, which includes its position — and an
  // inline `position:static` defeats the [data-hybrid-id]{position:relative}
  // stylesheet rule (inline wins). When the original is static, force relative
  // (relative with no offsets == static in flow, but establishes a containing
  // block). absolute/fixed/relative/sticky already establish one, so leave them.
  function withContainingBlock(style: string, pos: string): string {
    const p = (pos || "").trim();
    if (p && p !== "static") return style;
    return `${style};position:relative`;
  }
  function tryCanvasDataUri(canvas: HTMLCanvasElement): string | null {
    try { return canvas.toDataURL("image/png"); } catch { return null; }
  }
  function tryVideoDataUri(video: HTMLVideoElement): string | null {
    try {
      const c = document.createElement("canvas");
      c.width = video.videoWidth || video.clientWidth;
      c.height = video.videoHeight || video.clientHeight;
      if (!c.width || !c.height) return null;
      c.getContext("2d")!.drawImage(video, 0, 0, c.width, c.height);
      return c.toDataURL("image/png");
    } catch { return null; }
  }
  // STRICTLY canvas/video/cross-origin-iframe. Plain clip-path/mask/filter DOM
  // elements serialize losslessly as CSS and MUST stay in the DOM path. Treating
  // them as sidecars regressed fidelity in the lab (3.95% -> 0.02% once restricted).
  function isUnserializable(el: Element): SerializedSurface["kind"] | null {
    const tag = el.tagName.toLowerCase();
    if (tag === "canvas") return "canvas";
    if (tag === "video") return "video";
    if (tag === "iframe") {
      const src = el.getAttribute("src") || "";
      if (src && !sameOrigin(src)) return "iframe";
    }
    return null;
  }

  function clone(el: Element): Node {
    const kind = isUnserializable(el);
    if (kind) {
      const id = `hyb${surfaceSeq++}`;
      const rect = rectOf(el);
      let dataUri: string | null = null;
      if (kind === "canvas") dataUri = tryCanvasDataUri(el as HTMLCanvasElement);
      else if (kind === "video") dataUri = tryVideoDataUri(el as HTMLVideoElement);
      const { out, cs: pcs } = styleCss(el);
      const surface: SerializedSurface = {
        id, kind, rect, dataUri, needPlaywrightShot: !dataUri,
        clip: {
          borderRadius:
            pcs.getPropertyValue("border-top-left-radius") + " " +
            pcs.getPropertyValue("border-top-right-radius") + " " +
            pcs.getPropertyValue("border-bottom-right-radius") + " " +
            pcs.getPropertyValue("border-bottom-left-radius"),
          clipPath: pcs.getPropertyValue("clip-path"),
        },
      };
      surfaces.push(surface);
      const ph = document.createElement("div");
      ph.setAttribute("data-hybrid-id", id);
      ph.setAttribute("style", withContainingBlock(out, pcs.getPropertyValue("position")));
      return ph;
    }

    const tag = el.tagName.toLowerCase();

    // SVG subtree: preserve verbatim in the SVG namespace so <symbol>/<use> render.
    if ((el as Element).namespaceURI === SVGNS || tag === "svg") {
      el.querySelectorAll("use").forEach((u) => inlineExternalUse(u));
      const frag = new DOMParser().parseFromString(
        `<svg xmlns="${SVGNS}" xmlns:xlink="${XLINKNS}">${el.outerHTML}</svg>`,
        "image/svg+xml",
      );
      const parsed = frag.documentElement.firstElementChild;
      const { out: cssText } = styleCss(el);
      if (parsed && cssText) parsed.setAttribute("style", (parsed.getAttribute("style") || "") + cssText);
      return parsed || document.createElementNS(SVGNS, "g");
    }

    const out = document.createElement(tag === "html" ? "div" : tag);
    const { out: css, cs } = styleCss(el);
    if (css) out.setAttribute("style", css);

    const bg = cs.getPropertyValue("background-image");
    if (bg && bg.includes("url(")) {
      // Computed background-image URLs are already absolute; record for Node-side
      // inlining. The inline style keeps the absolute url(...) so the Node string
      // replace can swap it for the data-URI.
      const urlRe = /url\((['"]?)([^'")]+)\1\)/g;
      let bm: RegExpExecArray | null;
      while ((bm = urlRe.exec(bg))) {
        const u = bm[2];
        if (u && !u.startsWith("data:")) { const abs = toAbs(u); if (abs) bgUrls.push(abs); }
      }
    }
    for (const a of ["class", "id", "width", "height", "viewBox", "role", "dir", "lang"]) {
      if (el.hasAttribute(a)) out.setAttribute(a, el.getAttribute(a)!);
    }

    if (tag === "img") {
      const img = el as HTMLImageElement;
      const src = img.currentSrc || img.src;
      if (img.alt) out.setAttribute("alt", img.alt);
      if (src) {
        if (src.startsWith("data:")) {
          out.setAttribute("src", src);
        } else {
          // Keep the absolute URL + tag with an id; the Node side inlines it
          // (CORS-free) and, only if that fetch fails, rasterizes a sidecar here.
          const abs = toAbs(src) || src;
          out.setAttribute("src", abs);
          const id = `img${imgSeq++}`;
          out.setAttribute("data-hybrid-img", id);
          imgRefs.push({ id, url: abs, rect: rectOf(el) });
        }
      }
      return out;
    }
    if (tag === "input" || tag === "textarea" || tag === "select") {
      const field = el as HTMLInputElement;
      if (field.type) out.setAttribute("type", field.type);
      if (field.value != null) out.setAttribute("value", field.value);
      if (field.checked) out.setAttribute("checked", "");
      if (field.placeholder) out.setAttribute("placeholder", field.placeholder);
    }

    for (const pseudo of ["::before", "::after"]) {
      const ps = getComputedStyle(el, pseudo);
      const content = ps.getPropertyValue("content");
      if (content && content !== "none" && content !== "normal") {
        const { out: pcss } = styleCss(el, pseudo);
        const span = document.createElement("span");
        span.setAttribute("data-pseudo", pseudo);
        span.setAttribute("style", pcss);
        const txt = content.replace(/^["']|["']$/g, "");
        if (txt && txt !== "counter") span.textContent = txt;
        if (pseudo === "::before") out.insertBefore(span, out.firstChild);
        else out.appendChild(span);
      }
    }

    for (const node of Array.from(el.childNodes)) {
      if (node.nodeType === Node.TEXT_NODE) out.appendChild(document.createTextNode(node.nodeValue ?? ""));
      else if (node.nodeType === Node.ELEMENT_NODE) {
        const child = node as Element;
        const tn = child.tagName.toLowerCase();
        if (tn === "script" || tn === "noscript" || tn === "style" || tn === "link") continue;
        out.appendChild(clone(child));
      }
    }
    return out;
  }

  const scrolls: { sel: string; x: number; y: number }[] = [
    { sel: ":root", x: window.scrollX, y: window.scrollY },
  ];
  document.querySelectorAll("*").forEach((el, i) => {
    if (el.scrollTop || el.scrollLeft) {
      el.setAttribute("data-m5-scroll", `${i}`);
      scrolls.push({ sel: `[data-m5-scroll="${i}"]`, x: el.scrollLeft, y: el.scrollTop });
    }
  });

  const body = clone(document.body) as HTMLElement;

  async function drainTasks(): Promise<void> {
    let n = -1;
    while (fetchTasks.length + fontFaceTasks.length !== n) {
      n = fetchTasks.length + fontFaceTasks.length;
      await Promise.all([...fetchTasks, ...fontFaceTasks]);
    }
  }

  return drainTasks().then(() => {
    const rootStyle = styleCss(document.documentElement).out;
    const bgColor = getComputedStyle(document.documentElement).backgroundColor;
    const fontFaceCss = fontFaceBlocks.filter(Boolean).join("\n");
    let extDefs = "";
    if (externalSymbols.size) {
      extDefs =
        `<svg xmlns="${SVGNS}" width="0" height="0" style="position:absolute" aria-hidden="true">` +
        [...externalSymbols.values()].join("") + `</svg>`;
    }
    const payload: SerializedPayload = {
      rootStyle,
      bodyHtml: body.outerHTML,
      scrolls,
      surfaces,
      imgRefs,
      bgUrls,
      dpr: window.devicePixelRatio,
      vw: window.innerWidth,
      vh: window.innerHeight,
      lang: document.documentElement.lang || "",
      dir: document.documentElement.dir || "",
      bgColor,
      fontFaceCss,
      extDefs,
    };
    return JSON.stringify(payload);
  });
}

/**
 * In-page probe: does the page contain a registered custom element whose
 * shadowRoot is unreadable (closed)? That content is invisible to the in-page
 * DOM walk (m7) and must route to the CDP DOMSnapshot fallback (m4), which sees
 * Chromium's flattened render tree regardless of JS encapsulation.
 */
/* istanbul ignore next -- runs in the browser */
export function detectClosedShadowInPage(): boolean {
  const all = document.querySelectorAll("*");
  for (const el of Array.from(all)) {
    const tag = el.tagName.toLowerCase();
    if (!tag.includes("-")) continue; // custom elements only
    if (!customElements.get(tag)) continue; // registered
    // An open root is readable; a registered custom element with a null root is
    // either stateless OR closed. Heuristic: treat a null root on a registered
    // element that rendered a box as a closed root needing m4.
    if ((el as Element & { shadowRoot: ShadowRoot | null }).shadowRoot === null) {
      const r = el.getBoundingClientRect();
      if (r.width > 0 && r.height > 0) return true;
    }
  }
  return false;
}
