import { existsSync } from "node:fs";
import { mkdir, mkdtemp, rm, writeFile } from "node:fs/promises";
import { spawn } from "node:child_process";
import { tmpdir } from "node:os";
import { dirname, join } from "node:path";
import { pathToFileURL } from "node:url";

import { chromium, type Page } from "playwright-core";

import type { RenderFormat } from "./ffmpeg-transcode.js";
import { transcodeGif } from "./ffmpeg-transcode.js";

export type RenderSize = {
  width: number;
  height: number;
};

export type RenderedPack = {
  mp4?: string;
  webm?: string;
  poster?: string;
  gif?: string;
};

export type RecordHtmlOptions = {
  html: string;
  durationMs: number;
  size: RenderSize;
  formats: RenderFormat[];
  /** Output basename (no extension); each format appends its own. */
  outBase: string;
  fps?: number;
  deviceScaleFactor?: number;
};

// Determinism-first defaults. Frames are seek-stepped (no wall-clock pacing), so
// 60fps is purely an output-quality choice, not a capture-rate gamble. DPR2 gives
// vector-crisp output. Frames are PIPED to ffmpeg stdin — never written to disk —
// so DPR2/60fps does not blow up into multi-GB intermediates (the lab's trap).
export const DEFAULT_FRAME_RATE = 60;
export const DEFAULT_DEVICE_SCALE_FACTOR = 2;

const CHROMIUM_NOT_FOUND_MESSAGE = `✗ Chromium browser not found. Required for rendering compositions.

  Option 1 (recommended): npx playwright install chromium
  Option 2: set CHROME_PATH to your system Chrome (~200 MB savings)

Run one of the above and try again.`;

// Injected before the page loads. Virtualizes the JS clock so requestAnimationFrame
// / performance.now / Date.now-driven motion advances ONE step per seek instead of
// by wall-clock — making JS/rAF animation bit-for-bit deterministic. CSS/WAAPI
// animation and <video> are handled separately (seekDocumentAnimations/seekVideos).
const SEEK_CLOCK_SCRIPT = `(() => {
  let vt = 0;
  const realRAF = window.requestAnimationFrame.bind(window);
  let queue = new Map();
  let nextId = 1;
  window.requestAnimationFrame = (cb) => { const id = nextId++; queue.set(id, cb); return id; };
  window.cancelAnimationFrame = (id) => { queue.delete(id); };
  performance.now = () => vt;
  Date.now = () => vt;
  window.__composeSeek = (tMs) => {
    vt = tMs;
    const pending = queue; queue = new Map();
    for (const cb of pending.values()) { try { cb(tMs); } catch (e) {} }
  };
  // Real-rAF paint flush (double-rAF) so a screenshot captures the post-seek frame.
  window.__composeFlush = () => new Promise((resolve) => realRAF(() => realRAF(() => resolve())));
})();`;

export class ChromiumNotFoundError extends Error {
  constructor() {
    super(CHROMIUM_NOT_FOUND_MESSAGE);
    this.name = "ChromiumNotFoundError";
  }
}

export function resolveChromiumExecutable(): string | undefined {
  const candidates = [
    process.env.CHROME_PATH,
    "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
    "/Applications/Chromium.app/Contents/MacOS/Chromium",
    safePlaywrightExecutablePath(),
  ].filter(Boolean);

  for (const candidate of candidates) {
    if (candidate && existsSync(candidate)) return candidate;
  }

  return undefined;
}

/** Frame count for a duration at a given fps (>= 1). */
export function frameCountFor(durationMs: number, fps: number): number {
  return Math.max(1, Math.ceil((durationMs / 1000) * fps));
}

/**
 * Step a loaded page deterministically frame-by-frame, invoking `onFrame` with
 * each PNG screenshot buffer. No wall-clock pacing: each frame's content is fully
 * determined by its index, so re-runs are bit-for-bit identical.
 */
async function stepFrames(
  page: Page,
  durationMs: number,
  fps: number,
  onFrame: (frame: Buffer, index: number) => Promise<void>,
): Promise<number> {
  const frames = frameCountFor(durationMs, fps);
  for (let index = 0; index < frames; index += 1) {
    const tMs = (index / fps) * 1000;
    await seekVideos(page, tMs / 1000);
    await seekDocumentAnimations(page, tMs);
    await page.evaluate((t) => (window as unknown as ComposeWindow).__composeSeek?.(t), tMs);
    await page.evaluate(() => (window as unknown as ComposeWindow).__composeFlush?.());
    const frame = await page.screenshot({ type: "png" });
    await onFrame(frame, index);
  }
  return frames;
}

type ComposeWindow = {
  __composeSeek?: (tMs: number) => void;
  __composeFlush?: () => Promise<void>;
};

/**
 * Render a composition HTML document to the requested formats. Frames are
 * seek-stepped and streamed straight into per-format ffmpeg encoders (mp4 via
 * CRF-tuned H.264, webm via VP9) — encoded ONCE from the source screenshots, with
 * no intermediate video and no PNGs on disk. Poster is encoded from a mid-frame.
 */
export async function recordHtml(options: RecordHtmlOptions): Promise<RenderedPack> {
  const {
    html,
    durationMs,
    size,
    formats,
    outBase,
    fps = DEFAULT_FRAME_RATE,
    deviceScaleFactor = DEFAULT_DEVICE_SCALE_FACTOR,
  } = options;

  const executablePath = resolveChromiumExecutable();
  if (!executablePath) throw new ChromiumNotFoundError();

  await mkdir(dirname(outBase), { recursive: true });
  const tempDir = await mkdtemp(join(tmpdir(), "compose-record-"));

  const wantMp4 = formats.includes("mp4");
  const wantWebm = formats.includes("webm");
  const wantPoster = formats.includes("poster");
  const wantGif = formats.includes("gif");
  // gif derives from an mp4; produce one (to temp if mp4 not itself requested).
  const mp4Path = wantMp4 ? `${outBase}.mp4` : wantGif ? join(tempDir, "gif-source.mp4") : undefined;
  const webmPath = wantWebm ? `${outBase}.webm` : undefined;

  const encoders: Encoder[] = [];
  if (mp4Path) encoders.push(spawnEncoder(mp4EncodeArgs(fps, mp4Path)));
  if (webmPath) encoders.push(spawnEncoder(webmEncodeArgs(fps, webmPath)));

  const browser = await chromium.launch({ headless: true, executablePath });
  let posterFrame: Buffer | undefined;
  let totalFrames = 0;

  try {
    const context = await browser.newContext({ viewport: size, deviceScaleFactor });
    const page = await context.newPage();
    await page.addInitScript(SEEK_CLOCK_SCRIPT);
    const htmlPath = join(tempDir, "index.html");
    await writeFile(htmlPath, html, "utf8");
    await page.goto(pathToFileURL(htmlPath).href, { waitUntil: "networkidle" });
    await waitForVideos(page);
    await playVideos(page);

    const frames = frameCountFor(durationMs, fps);
    const posterIndex = Math.floor(frames / 2);

    totalFrames = await stepFrames(page, durationMs, fps, async (frame, index) => {
      if (index === posterIndex) posterFrame = frame;
      await Promise.all(encoders.map((encoder) => writeFrame(encoder, frame)));
    });

    await context.close();
  } catch (error) {
    for (const encoder of encoders) encoder.proc.kill();
    await rm(tempDir, { recursive: true, force: true });
    throw error;
  } finally {
    await browser.close();
  }

  try {
    for (const encoder of encoders) encoder.stdin.end();
    await Promise.all(encoders.map((encoder) => encoder.done));

    const pack: RenderedPack = {};
    if (wantMp4 && mp4Path) pack.mp4 = mp4Path;
    if (wantWebm && webmPath) pack.webm = webmPath;
    if (wantPoster) pack.poster = await encodePoster(posterFrame ?? (await firstFrameFallback()), `${outBase}.webp`);
    if (wantGif && mp4Path) pack.gif = await transcodeGif(mp4Path, `${outBase}.gif`);
    return pack;
  } finally {
    await rm(tempDir, { recursive: true, force: true });
  }

  async function firstFrameFallback(): Promise<Buffer> {
    throw new Error(`Poster requested but no frame was captured (frames=${totalFrames}).`);
  }
}

// ---- ffmpeg stdin encoders -------------------------------------------------

type Encoder = {
  proc: ReturnType<typeof spawn>;
  stdin: NodeJS.WritableStream;
  done: Promise<void>;
};

function spawnEncoder(args: string[]): Encoder {
  const proc = spawn("ffmpeg", args, { stdio: ["pipe", "ignore", "pipe"] });
  const stdin = proc.stdin;
  if (!stdin) throw new Error("ffmpeg stdin pipe unavailable.");
  let stderr = "";
  proc.stderr?.on("data", (chunk) => {
    stderr += String(chunk);
    if (stderr.length > 8192) stderr = stderr.slice(-8192);
  });
  const done = new Promise<void>((resolve, reject) => {
    proc.on("error", reject);
    proc.on("close", (code) => {
      if (code === 0) resolve();
      else reject(new Error(`ffmpeg encoder exited with code ${code}:\n${stderr}`));
    });
  });
  // Surface EPIPE etc. without crashing the process on early encoder death.
  stdin.on("error", () => {});
  return { proc, stdin, done };
}

function writeFrame(encoder: Encoder, frame: Buffer): Promise<void> {
  return new Promise((resolve, reject) => {
    encoder.stdin.write(frame, (error) => (error ? reject(error) : resolve()));
  });
}

function mp4EncodeArgs(fps: number, output: string): string[] {
  return [
    "-y",
    "-f", "image2pipe",
    "-framerate", String(fps),
    "-i", "-",
    "-c:v", "libx264",
    "-crf", "18",
    "-preset", "medium",
    "-pix_fmt", "yuv420p",
    "-movflags", "+faststart",
    output,
  ];
}

function webmEncodeArgs(fps: number, output: string): string[] {
  return [
    "-y",
    "-f", "image2pipe",
    "-framerate", String(fps),
    "-i", "-",
    "-c:v", "libvpx-vp9",
    "-b:v", "0",
    "-crf", "32",
    "-pix_fmt", "yuv420p",
    output,
  ];
}

function encodePoster(frame: Buffer, output: string): Promise<string> {
  return new Promise((resolve, reject) => {
    const proc = spawn(
      "ffmpeg",
      ["-y", "-f", "image2pipe", "-i", "-", "-frames:v", "1", "-c:v", "libwebp", "-quality", "85", output],
      { stdio: ["pipe", "ignore", "pipe"] },
    );
    let stderr = "";
    proc.stderr?.on("data", (chunk) => (stderr += String(chunk)));
    proc.on("error", reject);
    proc.on("close", (code) => (code === 0 ? resolve(output) : reject(new Error(`poster ffmpeg exited ${code}:\n${stderr}`))));
    proc.stdin.on("error", () => {});
    proc.stdin.end(frame);
  });
}

/**
 * Capture a composition's frames as in-memory PNG buffers (no disk, no encode).
 * For SHORT compositions only — used by the determinism gate and proof contact
 * sheets, which need direct frame access. Long clips should stream via recordHtml.
 */
export async function captureFrameBuffers(options: {
  html: string;
  durationMs: number;
  size: RenderSize;
  fps?: number;
  deviceScaleFactor?: number;
}): Promise<Buffer[]> {
  const {
    html,
    durationMs,
    size,
    fps = DEFAULT_FRAME_RATE,
    deviceScaleFactor = DEFAULT_DEVICE_SCALE_FACTOR,
  } = options;
  const executablePath = resolveChromiumExecutable();
  if (!executablePath) throw new ChromiumNotFoundError();

  const tempDir = await mkdtemp(join(tmpdir(), "compose-frames-"));
  const browser = await chromium.launch({ headless: true, executablePath });
  const frames: Buffer[] = [];
  try {
    const context = await browser.newContext({ viewport: size, deviceScaleFactor });
    const page = await context.newPage();
    await page.addInitScript(SEEK_CLOCK_SCRIPT);
    const htmlPath = join(tempDir, "index.html");
    await writeFile(htmlPath, html, "utf8");
    await page.goto(pathToFileURL(htmlPath).href, { waitUntil: "networkidle" });
    await waitForVideos(page);
    await playVideos(page);
    await stepFrames(page, durationMs, fps, async (frame) => {
      frames.push(frame);
    });
    await context.close();
    return frames;
  } finally {
    await browser.close();
    await rm(tempDir, { recursive: true, force: true });
  }
}

// ---- deterministic seeking (CSS/WAAPI + video) -----------------------------

async function playVideos(page: Page): Promise<void> {
  const failures = await page.evaluate(async () => {
    const videos = Array.from(document.querySelectorAll("video"));
    const errors: { src: string; message: string }[] = [];
    await Promise.all(
      videos.map(async (video) => {
        if (!video.currentSrc) return;
        video.currentTime = 0;
        try {
          await video.play();
        } catch (error) {
          errors.push({
            src: video.currentSrc,
            message: error instanceof Error ? error.message : String(error),
          });
        }
      }),
    );
    return errors;
  });

  if (failures.length > 0) {
    const summary = failures.map((f) => `  - ${f.src}: ${f.message}`).join("\n");
    throw new Error(`Composition video(s) failed to play; render would be black:\n${summary}`);
  }
}

async function seekVideos(page: Page, currentTimeSeconds: number): Promise<void> {
  await page.evaluate(async (currentTime) => {
    const videos = Array.from(document.querySelectorAll("video"));
    await Promise.all(
      videos.map(
        (video) =>
          new Promise<void>((resolve) => {
            if (!video.currentSrc) {
              resolve();
              return;
            }
            const done = () => resolve();
            const timeout = window.setTimeout(done, 250);
            video.addEventListener(
              "seeked",
              () => {
                window.clearTimeout(timeout);
                done();
              },
              { once: true },
            );
            video.currentTime = currentTime;
          }),
      ),
    );
  }, currentTimeSeconds);
}

async function seekDocumentAnimations(page: Page, currentTimeMs: number): Promise<void> {
  await page.evaluate((currentTime) => {
    for (const animation of document.documentElement.getAnimations({ subtree: true })) {
      animation.pause();
      animation.currentTime = currentTime;
    }
  }, currentTimeMs);
}

async function waitForVideos(page: Page): Promise<void> {
  await page.waitForFunction(
    () => {
      const videos = Array.from(document.querySelectorAll("video"));
      return videos.every((video) => !video.currentSrc || video.readyState >= 2);
    },
    undefined,
    { timeout: 8000 },
  );
}

function safePlaywrightExecutablePath(): string | undefined {
  try {
    return chromium.executablePath();
  } catch {
    return undefined;
  }
}
