// m7 hybrid (primary): m5-style computed-style DOM serialization PLUS a sidecar
// pass that rasterizes un-serializable surfaces (canvas / video / cross-origin
// iframe) and bakes them back into the artifact at pixel-correct geometry.
//
// Clean reimplementation of fidelity-lab/methods/m7_hybrid.mjs (and the m5 fixes
// it builds on) — see serialize.ts for the in-page walk. This file is the Node
// side: it fills sidecar pixels (inline dataURI where readable, else a Playwright
// element screenshot) and produces a SELF-CONTAINED standalone HTML document.

import type { Page } from "playwright-core";

import { inlineResolvedUris, resolveResourceUris } from "./resources.js";
import { serializeHybridInPage, type SerializedPayload, type SerializedSurface } from "./serialize.js";
import type { CaptureSnapshot, SurfaceMeta } from "./types.js";

/** Inject markup right after the opening <body …> tag (defs + sidecars). */
function injectIntoBody(bodyHtml: string, injected: string): string {
  if (!injected) return bodyHtml;
  const m = bodyHtml.match(/^(\s*<body[^>]*>)/i);
  if (m) return bodyHtml.slice(0, m[0].length) + injected + bodyHtml.slice(m[0].length);
  return injected + bodyHtml;
}

/**
 * Sidecar <img> for one rasterized surface, NESTED inside its placeholder
 * (inset:0) so it tracks the element's real layout position — robust to nested
 * flex/grid, transformed ancestors, and scroll containers. (The placeholder
 * carries position:relative via the [data-hybrid-id] rule.) The earlier
 * body-absolute page-coords approach misplaced sidecars deep in real app layouts.
 */
function sidecarImg(s: SerializedSurface): string {
  if (!s.dataUri) return "";
  const radius = s.clip?.borderRadius?.trim() ? `border-radius:${s.clip.borderRadius};` : "";
  const clipPath = s.clip?.clipPath && s.clip.clipPath !== "none" ? `clip-path:${s.clip.clipPath};` : "";
  const style = `position:absolute;inset:0;width:100%;height:100%;object-fit:fill;pointer-events:none;${radius}${clipPath}`;
  return `<img data-hybrid-sidecar="${s.id}" src="${s.dataUri}" style="${style}">`;
}

/** Insert each sidecar as the first child of its placeholder element. */
function injectSidecars(bodyHtml: string, surfaces: SerializedSurface[]): string {
  let html = bodyHtml;
  for (const s of surfaces) {
    const img = sidecarImg(s);
    if (!img) continue;
    const re = new RegExp(`(<[a-zA-Z][^>]*\\bdata-hybrid-id="${s.id}"[^>]*>)`);
    if (re.test(html)) html = html.replace(re, `$1${img}`);
  }
  return html;
}

/**
 * Snapshot the live page with the hybrid method. Returns a self-contained HTML
 * document plus per-surface metadata. Sidecars are BAKED into the HTML (the
 * placeholders stay visible so a surface's own CSS background/border shows behind
 * any transparent sidecar pixels — a faithfulness refinement over the lab, which
 * overlaid sidecars at remount time via a separate manifest).
 */
async function shotDataUri(page: Page, rect: SerializedSurface["rect"]): Promise<string | null> {
  try {
    const buf = await page.screenshot({
      clip: {
        x: Math.max(0, rect.vx),
        y: Math.max(0, rect.vy),
        width: Math.max(1, rect.w),
        height: Math.max(1, rect.h),
      },
    });
    return `data:image/png;base64,${buf.toString("base64")}`;
  } catch {
    return null;
  }
}

export async function snapshotM7(page: Page): Promise<CaptureSnapshot> {
  const payload = JSON.parse(await page.evaluate(serializeHybridInPage)) as SerializedPayload;

  // Resolve every external raster resource (content <img> + background-image)
  // on the NODE side via page.request — the browser's own network stack, immune
  // to the in-page CORS sandbox that blocked cross-origin/redirected/no-CORS
  // images. This is the same transport m4 uses; sharing it removes the entire
  // "image wouldn't inline → screenshot sidecar" failure class from m7.
  const dataUris = await resolveResourceUris(page, [
    ...payload.imgRefs.map((r) => r.url),
    ...payload.bgUrls,
  ]);

  // Last resort ONLY for content imgs the request context also couldn't fetch:
  // rasterize the element box and swap it into the img's own src. The <img> keeps
  // its real DOM geometry + object-fit, so no placeholder/positioning is needed.
  for (const ref of payload.imgRefs) {
    if (dataUris[ref.url]) continue;
    if (ref.rect.w < 1 || ref.rect.h < 1) continue;
    const uri = await shotDataUri(page, ref.rect);
    if (uri) dataUris[ref.url] = uri;
  }

  // Fill canvas/video/iframe sidecars that couldn't be read in-page (tainted
  // canvas / cross-origin iframe / unreadable video) via element-box screenshots.
  for (const s of payload.surfaces) {
    if (s.dataUri) continue;
    s.dataUri = await shotDataUri(page, s.rect);
  }

  // Inline every resolved URL, then bake surface sidecars. extDefs (clip-path
  // <svg> defs) go right after <body>; sidecars are NESTED inside their
  // placeholders so they track real nested layout geometry.
  const bodyInlined = inlineResolvedUris(payload.bodyHtml, dataUris);
  const bodyWithDefs = injectIntoBody(bodyInlined, payload.extDefs || "");
  const bodyWithInjections = injectSidecars(bodyWithDefs, payload.surfaces);

  const html =
    `<!doctype html><html lang="${payload.lang}" dir="${payload.dir}" style="${payload.rootStyle}">` +
    `<head><meta charset="utf-8"><meta name="viewport" content="width=${payload.vw}">` +
    `<style>html,body{margin:0;background:${payload.bgColor || "#fff"};}*{box-sizing:border-box;}` +
    `[data-hybrid-id]{position:relative;}</style>` +
    (payload.fontFaceCss ? `<style>${payload.fontFaceCss}</style>` : "") +
    `</head>${bodyWithInjections}</html>`;

  const surfaceMeta: SurfaceMeta[] = payload.surfaces.map((s) => ({
    id: s.id,
    kind: s.kind,
    rect: s.rect,
    rasterized: Boolean(s.dataUri),
    via: s.needPlaywrightShot ? "playwright" : "inline",
  }));

  return {
    method: "m7",
    html,
    scrolls: payload.scrolls,
    surfaces: surfaceMeta,
    notes: `m5 DOM + ${Object.keys(dataUris).length} resources inlined (node-side) + ${surfaceMeta.filter((s) => s.rasterized).length}/${surfaceMeta.length} surfaces rasterized`,
  };
}
