// Remount + screenshot helpers for the capture quality gate.
//
// A captured artifact is self-contained HTML (inlined fonts/images, baked
// sidecars). These helpers (1) take a deterministic LIVE screenshot of a URL,
// (2) remount an artifact and screenshot it at the SAME settings (so the diff is
// apples-to-apples and dimensions match the calibrated evaluator's requirement),
// and (3) render an artifact OFFLINE while counting network egress (proving it is
// truly self-contained for the Phase 1 renderer / Phase 4).

import { chromium, type Browser, type Page } from "playwright-core";

import { resolveChromiumExecutable, ChromiumNotFoundError } from "../render/playwright-driver.js";

export type CaptureSettings = {
  width: number;
  height: number;
  deviceScaleFactor: number;
};

export const DEFAULT_CAPTURE_SETTINGS: CaptureSettings = {
  width: 1000,
  height: 800,
  deviceScaleFactor: 2,
};

// Pin the raster path so live↔remount AA matches and re-renders are bit-stable
// (mirrors the lab's determinism args; FINDINGS noise floor ≈ 0%).
const LAUNCH_ARGS = [
  "--force-color-profile=srgb",
  "--disable-lcd-text",
  "--font-render-hinting=none",
  "--disable-skia-runtime-opts",
  "--hide-scrollbars",
];

export async function launchBrowser(): Promise<Browser> {
  const executablePath = resolveChromiumExecutable();
  if (!executablePath) throw new ChromiumNotFoundError();
  return chromium.launch({ headless: true, executablePath, args: LAUNCH_ARGS });
}

const KILL_ANIM_CSS =
  "*,*::before,*::after{animation:none!important;transition:none!important;caret-color:transparent!important;animation-play-state:paused!important;scroll-behavior:auto!important}";

/** Settle a page for a deterministic screenshot (fonts ready, animations killed). */
export async function settle(page: Page): Promise<void> {
  await page.addStyleTag({ content: KILL_ANIM_CSS }).catch(() => {});
  await page
    .evaluate(async () => {
      try { if (document.fonts?.ready) await document.fonts.ready; } catch { /* no fonts api */ }
      try { document.querySelectorAll("video,audio").forEach((m) => { const el = m as HTMLMediaElement; el.pause(); if (Number.isFinite(el.duration)) el.currentTime = 0; }); } catch { /* none */ }
      try { for (const a of document.getAnimations()) { a.currentTime = 0; a.pause(); } } catch { /* none */ }
    })
    .catch(() => {});
  await page
    .evaluate(() => new Promise<void>((r) => requestAnimationFrame(() => requestAnimationFrame(() => r()))))
    .catch(() => {});
}

async function viewportShot(page: Page): Promise<Buffer> {
  return page.screenshot({ type: "png" });
}

/**
 * Navigate deterministically. Real dashboards hold realtime/polling connections
 * open, so `networkidle` never fires and times out — use `domcontentloaded`, then
 * a BEST-EFFORT idle wait (so static pages still settle their assets), then a
 * fixed render window. Caller is expected to `settle(page)` afterwards.
 */
export async function navigate(page: Page, url: string, idleMs = 6000): Promise<import("playwright-core").Response | null> {
  const resp = await page.goto(url, { waitUntil: "domcontentloaded" });
  await page.waitForLoadState("networkidle", { timeout: idleMs }).catch(() => {});
  await settleDynamicContent(page);
  await page.waitForTimeout(400);
  return resp;
}

/**
 * Wait for client-rendered content (dashboard lists/data) to stop growing, so the
 * classifier and live screenshot see the POPULATED DOM, not a mid-hydration skeleton.
 * Real dashboards load their data async after domcontentloaded; without this, an
 * authenticated /app screen intermittently classifies as "no homogeneous data
 * structure" on a cold load. Bounded (early-exits once innerText length is stable).
 */
async function settleDynamicContent(page: Page, maxIters = 8, stepMs = 600): Promise<void> {
  let prev = -1;
  for (let i = 0; i < maxIters; i += 1) {
    const len = await page.evaluate(() => (document.body?.innerText || "").length).catch(() => prev);
    if (len === prev) return;
    prev = len;
    await page.waitForTimeout(stepMs);
  }
}

/**
 * Auth context for capturing screens behind a login. Playwright's native
 * storageState shape (cookies + per-origin localStorage) — lets the capture
 * pipeline reach authenticated `/app/*` screens. Built by the CLI (demo bootstrap
 * or a real session) and threaded through evaluateUrl/captureUrl.
 */
export type CaptureStorageState = {
  cookies?: unknown[];
  origins?: { origin: string; localStorage: { name: string; value: string }[] }[];
};

/** Open a context with capture settings (and optional auth) applied before navigation. */
export async function openPage(
  browser: Browser,
  settings: CaptureSettings,
  storageState?: CaptureStorageState,
): Promise<Page> {
  const context = await browser.newContext({
    viewport: { width: settings.width, height: settings.height },
    deviceScaleFactor: settings.deviceScaleFactor,
    reducedMotion: "reduce",
    colorScheme: "light",
    locale: "en-US",
    timezoneId: "UTC",
    ...(storageState ? { storageState: storageState as never } : {}),
  });
  return context.newPage();
}

/** Remount artifact HTML and screenshot it at the given settings. */
export async function remountScreenshot(
  html: string,
  scrolls: { sel: string; x: number; y: number }[],
  settings: CaptureSettings = DEFAULT_CAPTURE_SETTINGS,
): Promise<Buffer> {
  const browser = await launchBrowser();
  try {
    const page = await openPage(browser, settings);
    await page.setContent(html, { waitUntil: "load" });
    await page.evaluate(() => document.fonts?.ready).catch(() => {});
    await restoreScroll(page, scrolls);
    await settle(page);
    return await viewportShot(page);
  } finally {
    await browser.close();
  }
}

async function restoreScroll(page: Page, scrolls: { sel: string; x: number; y: number }[]): Promise<void> {
  await page
    .evaluate((list) => {
      for (const s of list) {
        if (s.sel === ":root") { window.scrollTo(s.x, s.y); continue; }
        const el = document.querySelector(s.sel);
        if (el) { el.scrollLeft = s.x; el.scrollTop = s.y; }
      }
    }, scrolls)
    .catch(() => {});
}

/**
 * Render artifact HTML offline and count network egress. A self-contained
 * artifact must make ZERO http(s) requests — every asset is a data-URI.
 */
export async function renderArtifactOffline(
  html: string,
  settings: CaptureSettings = DEFAULT_CAPTURE_SETTINGS,
): Promise<{ networkRequests: string[]; png: Buffer }> {
  const browser = await launchBrowser();
  try {
    const page = await openPage(browser, settings);
    const networkRequests: string[] = [];
    page.on("request", (req) => {
      const url = req.url();
      if (url.startsWith("http://") || url.startsWith("https://")) networkRequests.push(url);
    });
    await page.setContent(html, { waitUntil: "load" });
    await page.evaluate(() => document.fonts?.ready).catch(() => {});
    await settle(page);
    const png = await viewportShot(page);
    return { networkRequests, png };
  } finally {
    await browser.close();
  }
}

/** Take a deterministic live screenshot of a URL at the given settings. */
export async function liveScreenshot(
  url: string,
  settings: CaptureSettings = DEFAULT_CAPTURE_SETTINGS,
): Promise<Buffer> {
  const browser = await launchBrowser();
  try {
    const page = await openPage(browser, settings);
    await navigate(page, url);
    await settle(page);
    return await viewportShot(page);
  } finally {
    await browser.close();
  }
}
